import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RiskStatus {
  STABLE = 'STABLE',
  CAUTION = 'CAUTION',
  RISKY = 'RISKY'
}

export interface Supplier {
  id: string;
  name: string;
  category: string;
  location: string;
  coordinates: [number, number]; // [lat, lng]
  status: RiskStatus;
  contactEmail: string;
  lastUpdated: string;
}

export interface Disruption {
  id: string;
  title: string;
  type: 'Weather' | 'Strike' | 'Incident' | 'Logistics';
  severity: 'High' | 'Medium' | 'Low';
  location: string;
  timestamp: string;
  summary: string;
  impactedSuppliers: string[]; // Supplier IDs
}

export interface IntelligenceBrief {
  supplierId: string;
  summary: string;
  weatherStatus: string;
  recentNews: string[];
  historicalContext: string;
  recommendations: string[];
  alternativeSuppliers: string[];
  lastUpdated: string;
  sources: { title: string; uri: string }[];
}

export type View = 'DASHBOARD' | 'REGISTRY' | 'INTELLIGENCE' | 'MAP' | 'FEED' | 'SETTINGS';

import { GoogleGenAI, Type } from "@google/genai";
import { IntelligenceBrief, Supplier } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateSupplierIntelligence = async (supplier: Supplier): Promise<IntelligenceBrief> => {
  const prompt = `Provide a comprehensive supply chain intelligence brief for ${supplier.name} located in ${supplier.location}.
  Include:
  1. A risk summary of current operations.
  2. Real-time weather impact on their specific region.
  3. Recent news (within the last 7 days) affecting their industry or location.
  4. Historical context of disruptions for this region.
  5. Actionable recommendations to mitigate risk.
  6. Two alternative suppliers for ${supplier.category}.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            weatherStatus: { type: Type.STRING },
            recentNews: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            historicalContext: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            alternativeSuppliers: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["summary", "weatherStatus", "recentNews", "historicalContext", "recommendations", "alternativeSuppliers"]
        }
      },
    });

    const jsonText = response.text || "{}";
    const data = JSON.parse(jsonText);

    // Extract grounding sources if available
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Search Result",
      uri: chunk.web?.uri || "#"
    })) || [];

    return {
      supplierId: supplier.id,
      summary: data.summary,
      weatherStatus: data.weatherStatus,
      recentNews: data.recentNews,
      historicalContext: data.historicalContext,
      recommendations: data.recommendations,
      alternativeSuppliers: data.alternativeSuppliers,
      lastUpdated: new Date().toISOString(),
      sources: sources
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

