import React from 'react';
import { RiskStatus } from '../types';

interface RiskBadgeProps {
  status: RiskStatus;
  size?: 'sm' | 'md' | 'lg';
}

const RiskBadge: React.FC<RiskBadgeProps> = ({ status, size = 'md' }) => {
  const styles = {
    [RiskStatus.STABLE]: 'bg-emerald-50 text-emerald-700 border-emerald-100',
    [RiskStatus.CAUTION]: 'bg-amber-50 text-amber-700 border-amber-100',
    [RiskStatus.RISKY]: 'bg-rose-50 text-rose-700 border-rose-100',
  };

  const sizes = {
    sm: 'px-2 py-0.5 text-[10px]',
    md: 'px-2.5 py-1 text-xs',
    lg: 'px-4 py-1.5 text-sm',
  };

  return (
    <span className={`inline-flex items-center font-bold rounded-full border ${styles[status]} ${sizes[size]} uppercase tracking-wider`}>
      <span className={`w-1.5 h-1.5 rounded-full mr-1.5 ${
        status === RiskStatus.STABLE ? 'bg-emerald-500' : 
        status === RiskStatus.CAUTION ? 'bg-amber-500' : 'bg-rose-500'
      }`} />
      {status}
    </span>
  );
};

