  supplier: Supplier;
  onBack: () => void;
}

const IntelligenceView: React.FC<IntelligenceViewProps> = ({ supplier, onBack }) => {
  const [brief, setBrief] = useState<IntelligenceBrief | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchIntelligence = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await generateSupplierIntelligence(supplier);
      setBrief(data);
    } catch (err) {
      setError("Failed to generate intelligence brief. Please ensure your API key is valid and try again.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchIntelligence();
  }, [supplier.id]);

  if (loading) {
    return (
      <div className="h-full flex flex-col items-center justify-center p-8 space-y-6 text-center animate-pulse">
        <div className="w-16 h-16 border-4 border-slate-900 border-t-transparent rounded-full animate-spin" />
