      return (
        <div className="bg-white p-3 border border-slate-200 shadow-xl rounded-xl">
          <p className="text-xs font-black uppercase tracking-widest text-slate-400 mb-1">{payload[0].name}</p>
          <p className="text-lg font-bold text-slate-900">{payload[0].value} Suppliers ({payload[0].payload.percentage}%)</p>
        </div>
      );
