          </p>
        </div>
        <div className="flex gap-4">
          <button className="px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-50 transition-all shadow-sm">
            Export Data
          </button>
          <button className="px-5 py-3 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-lg shadow-slate-200 flex items-center gap-2">
            Global Resync <TrendingUp size={18} />
          </button>
        </div>
      </div>

      {/* Clickable KPI Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat) => (
          <button 
            key={stat.id} 
            onClick={() => onStatusFilterChange(stat.status as any)}
            className={`text-left bg-white p-7 rounded-3xl border transition-all group relative overflow-hidden ${
              statusFilter === stat.status 
                ? 'border-slate-900 ring-2 ring-slate-900 shadow-xl' 
                : 'border-slate-200 shadow-sm hover:shadow-xl hover:border-slate-300'
            }`}
          >
            <div className={`inline-flex p-4 rounded-2xl ${stat.bg} ${stat.color} mb-6 transition-transform group-hover:scale-110`}>
              <stat.icon size={26} />
