import React, { useState, useEffect } from 'react';
import { View, Supplier, User, RiskStatus } from './types';
import Layout from './components/Layout';
import AuthView from './views/AuthView';
import DashboardView from './views/DashboardView';
import RegistryView from './views/RegistryView';
import IntelligenceView from './views/IntelligenceView';
import MapView from './views/MapView';
import FeedView from './views/FeedView';
import SettingsView from './views/SettingsView';

const App: React.FC = () => {
  const [view, setView] = useState<View>('DASHBOARD');
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('cg_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [categoryFilter, setCategoryFilter] = useState<string>('ALL');
  const [statusFilter, setStatusFilter] = useState<RiskStatus | 'ALL'>('ALL');
  const [selectedSupplier, setSelectedSupplier] = useState<Supplier | null>(null);

  const handleAuthComplete = (userData: User) => {
    setUser(userData);
    localStorage.setItem('cg_session', JSON.stringify(userData));
  };

  const handleLogout = () => {
    localStorage.removeItem('cg_session');
    setUser(null);
  };

  const navigateToSupplierIntelligence = (supplier: Supplier) => {
    setSelectedSupplier(supplier);
    setView('INTELLIGENCE');
  };

  if (!user) {
    return <AuthView onComplete={handleAuthComplete} />;
  }

  const renderView = () => {
    switch (view) {
      case 'DASHBOARD':
        return (
          <DashboardView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            onNavigateToRegistry={() => setView('REGISTRY')}
          />
        );
      case 'REGISTRY':
        return (
          <RegistryView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            onSelectSupplier={navigateToSupplierIntelligence} 
          />
        );
      case 'INTELLIGENCE':
        return selectedSupplier ? (
          <IntelligenceView supplier={selectedSupplier} onBack={() => setView('REGISTRY')} />
        ) : (
          <RegistryView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            onSelectSupplier={navigateToSupplierIntelligence} 
          />
        );
      case 'MAP':
        return (
          <MapView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onSelectSupplier={navigateToSupplierIntelligence}
          />
        );
      case 'FEED':
        return <FeedView categoryFilter={categoryFilter} />;
      case 'SETTINGS':
        return <SettingsView user={user} />;
      default:
        return <DashboardView 
          categoryFilter={categoryFilter}
          statusFilter={statusFilter}
          onStatusFilterChange={setStatusFilter}
          onNavigateToRegistry={() => setView('REGISTRY')}
        />;
    }
  };

  return (
    <Layout 
      activeView={view} 
      onViewChange={setView} 
      onLogout={handleLogout}
      companyName={user.company}
      role={user.role}
      categoryFilter={categoryFilter}
      onCategoryFilterChange={setCategoryFilter}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

