import React, { useState } from 'react';
import { MOCK_SUPPLIERS } from '../constants';
import { Supplier, RiskStatus } from '../types';
import RiskBadge from '../components/RiskBadge';
import { Search, ChevronRight, MapPin, Mail } from 'lucide-react';

interface RegistryViewProps {
  categoryFilter: string;
  statusFilter: RiskStatus | 'ALL';
  onStatusFilterChange: (s: RiskStatus | 'ALL') => void;
  onSelectSupplier: (supplier: Supplier) => void;
}

const RegistryView: React.FC<RegistryViewProps> = ({ 
  categoryFilter, 
  statusFilter, 
  onStatusFilterChange, 
  onSelectSupplier 
}) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredSuppliers = MOCK_SUPPLIERS.filter(s => {
    const matchesSearch = s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         s.category.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = categoryFilter === 'ALL' || s.category === categoryFilter;
    const matchesStatus = statusFilter === 'ALL' || s.status === statusFilter;
    return matchesSearch && matchesCategory && matchesStatus;
  });

  return (
    <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Network Registry</h2>
          <p className="text-slate-500 font-medium mt-1">
            Monitoring {filteredSuppliers.length} active global partners.
          </p>
        </div>

        <div className="flex flex-wrap items-center gap-4">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text"
              placeholder="Filter by name..."
              className="pl-11 pr-4 py-3 bg-white border border-slate-300 rounded-2xl w-64 focus:ring-2 focus:ring-slate-900 outline-none transition-all text-slate-900 placeholder:text-slate-400 font-medium shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-2 bg-white border border-slate-200 p-1.5 rounded-2xl shadow-sm">
            {(['ALL', RiskStatus.STABLE, RiskStatus.CAUTION, RiskStatus.RISKY] as const).map((f) => (
              <button
                key={f}
                onClick={() => onStatusFilterChange(f)}
                className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
                  statusFilter === f 
                    ? 'bg-slate-900 text-white shadow-lg' 
                    : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-200 shadow-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Supplier Profile</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Asset Class</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Geography</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Risk Status</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredSuppliers.map((supplier) => (
                <tr 
                  key={supplier.id}
                  onClick={() => onSelectSupplier(supplier)}
                  className="hover:bg-slate-50 transition-colors cursor-pointer group"
                >
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center font-black text-white group-hover:scale-105 transition-transform shadow-md">
                        {supplier.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-extrabold text-slate-900 text-base">{supplier.name}</p>
                        <p className="text-xs text-slate-400 flex items-center gap-1.5 mt-1 font-medium">
                          <Mail size={12} /> {supplier.contactEmail}
                        </p>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <span className="text-xs font-bold text-slate-600 bg-slate-100 px-3 py-1.5 rounded-lg border border-slate-200">
                      {supplier.category}
                    </span>
                  </td>
                  <td className="px-8 py-6">
                    <p className="text-sm text-slate-600 flex items-center gap-2 font-medium">
                      <MapPin size={14} className="text-slate-400" /> {supplier.location}
                    </p>
                  </td>
                  <td className="px-8 py-6">
                    <RiskBadge status={supplier.status} size="md" />
                  </td>
                  <td className="px-8 py-6 text-right">
                    <button className="p-3 hover:bg-white hover:shadow-md rounded-xl transition-all text-slate-400 group-hover:text-slate-900">
                      <ChevronRight size={20} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filteredSuppliers.length === 0 && (
          <div className="p-24 text-center">
            <div className="inline-flex p-6 bg-slate-50 rounded-full mb-6 border border-slate-100">
              <Search size={40} className="text-slate-300" />
            </div>
            <p className="text-slate-500 font-bold text-lg">No partners match the active intelligence filters.</p>
            <button 
              onClick={() => { setSearchTerm(''); onStatusFilterChange('ALL'); }}
              className="mt-4 text-blue-600 font-bold text-sm underline underline-offset-4"
            >
              Reset Global Filters
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default RegistryView;

import React from 'react';
