import React from 'react';
import { MOCK_SUPPLIERS, MOCK_DISRUPTIONS } from '../constants';
import { RiskStatus, Supplier } from '../types';
import { 
  AlertTriangle, 
  CheckCircle2, 
  Activity, 
  TrendingUp,
  Clock,
  ArrowUpRight,
  Target
} from 'lucide-react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer } from 'recharts';

interface DashboardViewProps {
  categoryFilter: string;
  statusFilter: RiskStatus | 'ALL';
  onStatusFilterChange: (status: RiskStatus | 'ALL') => void;
  onNavigateToRegistry: () => void;
  onNavigateToFeed: () => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ 
  categoryFilter, 
  statusFilter, 
  onStatusFilterChange,
  onNavigateToRegistry,
  onNavigateToFeed
}) => {
  // Filter data based on global category
  const channelSuppliers = MOCK_SUPPLIERS.filter(s => {
    return categoryFilter === 'ALL' || s.category === categoryFilter;
  });

  const getCountByStatus = (status: RiskStatus) => channelSuppliers.filter(s => s.status === status).length;

  const stableCount = getCountByStatus(RiskStatus.STABLE);
  const cautionCount = getCountByStatus(RiskStatus.CAUTION);
  const riskyCount = getCountByStatus(RiskStatus.RISKY);
  const totalCount = channelSuppliers.length;

  // Visual representation adjustment: if a specific status is filtered, 
  // we highlight that status or show the filtered subset.
  const chartData = [
    { name: 'Stable', value: stableCount, color: '#059669', percentage: Math.round((stableCount/totalCount)*100) || 0, id: RiskStatus.STABLE },
    { name: 'Caution', value: cautionCount, color: '#D97706', percentage: Math.round((cautionCount/totalCount)*100) || 0, id: RiskStatus.CAUTION },
    { name: 'Risky', value: riskyCount, color: '#DC2626', percentage: Math.round((riskyCount/totalCount)*100) || 0, id: RiskStatus.RISKY },
  ].filter(d => d.value > 0).map(item => ({
    ...item,
    // Dim other segments if a specific status is filtered
    color: statusFilter === 'ALL' || statusFilter === item.id ? item.color : `${item.color}44`
  }));

  const stats = [
    { id: 'ALL', label: 'Network Total', value: totalCount, icon: Target, color: 'text-slate-600', bg: 'bg-slate-100', status: 'ALL' },
    { id: RiskStatus.RISKY, label: 'High Risk Nodes', value: riskyCount, icon: AlertTriangle, color: 'text-rose-600', bg: 'bg-rose-50', status: RiskStatus.RISKY },
    { id: RiskStatus.CAUTION, label: 'Active Caution', value: cautionCount, icon: Activity, color: 'text-amber-600', bg: 'bg-amber-50', status: RiskStatus.CAUTION },
    { id: RiskStatus.STABLE, label: 'Operational Sync', value: stableCount, icon: CheckCircle2, color: 'text-emerald-600', bg: 'bg-emerald-50', status: RiskStatus.STABLE },
  ];

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white p-3 border border-slate-200 shadow-xl rounded-xl">
          <p className="text-xs font-black uppercase tracking-widest text-slate-400 mb-1">{payload[0].name}</p>
          <p className="text-lg font-bold text-slate-900">{payload[0].value} Suppliers ({payload[0].payload.percentage}%)</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Executive Intelligence</h2>
          <p className="text-slate-500 mt-2 font-medium flex items-center gap-2">
            <Clock size={16} className="text-blue-500" /> System sync completed {new Date().toLocaleTimeString()} • <span className="text-slate-900 font-bold">{categoryFilter}</span> Channel
          </p>
        </div>
        <div className="flex gap-4">
          <button className="px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-50 transition-all shadow-sm">
            Export Data
          </button>
          <button className="px-5 py-3 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-lg shadow-slate-200 flex items-center gap-2">
            Global Resync <TrendingUp size={18} />
          </button>
        </div>
      </div>

      {/* Clickable KPI Cards - Selecting a card changes visual representation */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat) => (
          <button 
            key={stat.id} 
            onClick={() => onStatusFilterChange(stat.status as any)}
            className={`text-left bg-white p-7 rounded-3xl border transition-all group relative overflow-hidden h-full ${
              statusFilter === stat.status 
                ? 'border-slate-900 ring-2 ring-slate-900 shadow-xl' 
                : 'border-slate-200 shadow-sm hover:shadow-xl hover:border-slate-300'
            }`}
          >
            <div className={`inline-flex p-4 rounded-2xl ${stat.bg} ${stat.color} mb-6 transition-transform group-hover:scale-110`}>
              <stat.icon size={26} />
            </div>
            <p className="text-slate-500 font-bold text-xs uppercase tracking-widest">{stat.label}</p>
            <h3 className="text-4xl font-black text-slate-900 mt-2">{stat.value}</h3>
            {statusFilter === stat.status && (
              <div className="absolute top-4 right-4 text-[10px] font-black text-slate-900 uppercase">Selected Filter</div>
            )}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-10">
        {/* Risk Distribution Chart - Executive Donut */}
        <div className="xl:col-span-2 bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-sm flex flex-col items-center justify-center relative overflow-hidden min-h-[500px]">
          <div className="absolute top-10 left-10">
            <h3 className="text-2xl font-black text-slate-900">Network Resilience</h3>
            <p className="text-slate-400 font-medium text-sm mt-1">Status distribution by node count</p>
          </div>

          <div className="w-full h-[400px] mt-10">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={110}
                  outerRadius={150}
                  paddingAngle={8}
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={800}
                >
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} strokeWidth={0} className="outline-none" />
                  ))}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
              </PieChart>
            </ResponsiveContainer>

            {/* Center Text for Donut */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center mt-5">
              <p className="text-4xl font-black text-slate-900">
                {statusFilter === 'ALL' ? totalCount : channelSuppliers.filter(s => s.status === statusFilter).length}
              </p>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">
                {statusFilter === 'ALL' ? 'Active Nodes' : `${statusFilter} Nodes`}
              </p>
            </div>
          </div>

          <div className="flex flex-wrap gap-10 mt-6 justify-center">
            {chartData.map((item, i) => (
              <button 
                key={i} 
                onClick={() => onStatusFilterChange(item.id as RiskStatus)}
                className={`flex items-center gap-3 transition-all ${statusFilter !== 'ALL' && statusFilter !== item.id ? 'opacity-30 scale-95' : 'scale-100'}`}
              >
                <div className="w-3 h-3 rounded-full" style={{backgroundColor: item.color.length > 7 ? item.color.slice(0, 7) : item.color}} />
                <div className="text-left">
                  <p className="text-xs font-black text-slate-900 uppercase tracking-tight">{item.name}</p>
                  <p className="text-sm font-bold text-slate-400">{item.percentage}%</p>
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Risk Signals Side-Feed - Clickable to land on disruption feed page */}
        <div className="bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-2xl font-black text-slate-900">Risk Signals</h3>
            <button 
              onClick={onNavigateToFeed}
              className="p-2 bg-slate-50 hover:bg-slate-100 rounded-xl transition-all"
            >
              <ArrowUpRight size={20} className="text-slate-900" />
            </button>
          </div>
          <div className="space-y-5 flex-1 overflow-y-auto pr-2 custom-scrollbar">
            {MOCK_DISRUPTIONS.filter(d => categoryFilter === 'ALL' || d.type === categoryFilter || d.type === 'Logistics').map((d) => (
              <button 
                key={d.id} 
                onClick={onNavigateToFeed}
                className="w-full text-left p-6 rounded-[1.5rem] border border-slate-100 bg-slate-50 hover:bg-white hover:border-slate-200 hover:shadow-lg transition-all group"
              >
                <div className="flex items-center justify-between mb-3">
                  <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${
                    d.severity === 'High' ? 'bg-rose-100 text-rose-700' : 'bg-amber-100 text-amber-700'
                  }`}>
                    {d.severity} Priority
                  </span>
                  <span className="text-[10px] font-bold text-slate-400">{d.type}</span>
                </div>
                <h4 className="font-extrabold text-slate-900 text-base leading-tight mb-3">{d.title}</h4>
                <p className="text-sm text-slate-500 line-clamp-2 leading-relaxed">{d.summary}</p>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;

