          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Spatial Intelligence</h2>
          <p className="text-slate-500 font-medium mt-1 uppercase text-xs tracking-widest">
            {filteredSuppliers.length} Nodes Mapped • {categoryFilter} Network • {statusFilter} Status
          </p>
        </div>
        <div className="flex items-center gap-6 bg-white px-6 py-3 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-2">
            <span className="w-3 h-3 rounded-full bg-emerald-500 shadow-sm" />
            <span className="text-[10px] font-black text-slate-900 uppercase">Stable</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="w-3 h-3 rounded-full bg-amber-500 shadow-sm" />
            <span className="text-[10px] font-black text-slate-900 uppercase">Caution</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="w-3 h-3 rounded-full bg-rose-500 shadow-sm" />
            <span className="text-[10px] font-black text-slate-900 uppercase">Risky</span>
          </div>
        </div>
      </div>

      <div className="relative flex-1 bg-slate-900 rounded-[3rem] overflow-hidden shadow-2xl border border-slate-800 min-h-[500px]">
        {/* Risk Intensity Overlays - Dynamic circles based on risky suppliers */}
        <div className="absolute inset-0 pointer-events-none opacity-40">
          {MOCK_SUPPLIERS.filter(s => s.status === RiskStatus.RISKY).map((s, i) => {
             const { x, y } = getCoordinates(s.coordinates[0], s.coordinates[1]);
             return (
               <div 
                key={`overlay-${i}`}
                className="absolute w-[300px] h-[300px] bg-rose-500/10 rounded-full blur-[80px]"
                style={{ left: `calc(${(x/800)*100}% - 150px)`, top: `calc(${(y/400)*100}% - 150px)` }}
               />
             )
          })}
        </div>

        <svg viewBox="0 0 800 400" className="w-full h-full opacity-40 select-none">
          <path 
            d="M 50,200 L 150,180 L 250,210 L 350,190 L 450,220 L 550,200 L 650,210 L 750,190" 
            fill="none" 
            stroke="white" 
            strokeWidth="0.5" 
            strokeDasharray="5,5"
            className="opacity-20"
          />
          <text x="50%" y="95%" textAnchor="middle" fill="white" className="text-[10px] font-black uppercase tracking-[0.4em] opacity-30">Enterprise Satellite Feed Layer</text>
        </svg>

        {filteredSuppliers.map((s) => {
          const { x, y } = getCoordinates(s.coordinates[0], s.coordinates[1]);
          return (
            <div 
              key={s.id}
              className="absolute transition-all cursor-pointer z-10"
              style={{ left: `${(x/800)*100}%`, top: `${(y/400)*100}%` }}
              onMouseEnter={() => setHovered(s)}
              onMouseLeave={() => setHovered(null)}
              onClick={() => onSelectSupplier(s)}
            >
              <div className={`relative flex items-center justify-center w-10 h-10 -translate-x-1/2 -translate-y-1/2 group`}>
                <div className={`absolute w-full h-full rounded-full transition-all duration-1000 group-hover:scale-150 ${
                  s.status === RiskStatus.STABLE ? 'bg-emerald-500/20' :
                  s.status === RiskStatus.CAUTION ? 'bg-amber-500/20' : 'bg-rose-500/20'
                }`} />
                <div className={`w-5 h-5 rounded-full border-4 border-slate-900 shadow-2xl transition-transform group-hover:scale-125 ${
                  s.status === RiskStatus.STABLE ? 'bg-emerald-500' :
                  s.status === RiskStatus.CAUTION ? 'bg-amber-500' : 'bg-rose-500'
                }`} />
              </div>
            </div>
          );
        })}

        {/* Compact Hover Tooltip */}
        {hovered && (
          <div 
            className="absolute z-30 pointer-events-none transition-all animate-in zoom-in-95 duration-200"
            style={{ 
              left: `calc(${(getCoordinates(hovered.coordinates[0], hovered.coordinates[1]).x/800)*100}% + 16px)`, 
              top: `calc(${(getCoordinates(hovered.coordinates[0], hovered.coordinates[1]).y/400)*100}% - 40px)` 
            }}
          >
            <div className="bg-white rounded-xl shadow-xl border border-slate-200 px-3 py-2 flex items-center gap-3">
              <span className="font-bold text-slate-900 text-sm whitespace-nowrap">{hovered.name}</span>
              <RiskBadge status={hovered.status} size="sm" />
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center gap-5">
          <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
            <Target size={28} />
          </div>
          <div>
            <h4 className="font-black text-slate-900 uppercase text-[10px] tracking-widest mb-1 text-slate-400">Regional Coverage</h4>
            <p className="font-bold text-slate-800">100% Visibility</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center gap-5">
          <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center">
            <Info size={28} />
          </div>
          <div>
            <h4 className="font-black text-slate-900 uppercase text-[10px] tracking-widest mb-1 text-slate-400">Node Sync</h4>
            <p className="font-bold text-slate-800">Active Handshake</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center gap-5">
          <div className="w-14 h-14 bg-slate-900 text-white rounded-2xl flex items-center justify-center">
            <Search size={28} />
          </div>
          <div>
            <h4 className="font-black text-slate-900 uppercase text-[10px] tracking-widest mb-1 text-slate-400">Data Integrity</h4>
            <p className="font-bold text-slate-800">Verified Signals</p>
          </div>
        </div>
      </div>
