import MapView from './views/MapView';
import FeedView from './views/FeedView';
import SettingsView from './views/SettingsView';
import SubscriptionView from './views/SubscriptionView';

const App: React.FC = () => {
  const [view, setView] = useState<View>('DASHBOARD');
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('cg_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [categoryFilter, setCategoryFilter] = useState<string>('ALL');
  const [statusFilter, setStatusFilter] = useState<RiskStatus | 'ALL'>('ALL');
  const [selectedSupplier, setSelectedSupplier] = useState<Supplier | null>(null);

  const handleAuthComplete = (userData: User) => {
    setUser(userData);
    localStorage.setItem('cg_session', JSON.stringify(userData));
  };

  const handleLogout = () => {
    localStorage.removeItem('cg_session');
    setUser(null);
  };

  const navigateToSupplierIntelligence = (supplier: Supplier) => {
    setSelectedSupplier(supplier);
  };

  if (!user) {
    return <AuthView onComplete={handleAuthComplete} />;
  }

  const renderView = () => {
    switch (view) {
      case 'DASHBOARD':
        return (
          <DashboardView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            onNavigateToRegistry={() => setView('REGISTRY')}
            onNavigateToFeed={() => setView('FEED')}
          />
        );
      case 'REGISTRY':
        return (
          <RegistryView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            onSelectSupplier={navigateToSupplierIntelligence} 
          />
        );
      case 'MAP':
        return (
          <MapView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onSelectSupplier={navigateToSupplierIntelligence}
          />
        );
      case 'FEED':
        return <FeedView categoryFilter={categoryFilter} />;
      case 'SETTINGS':
        return <SettingsView user={user} onNavigate={setView} />;
      case 'SUBSCRIPTION':
        return <SubscriptionView onBack={() => setView('SETTINGS')} />;
      default:
        return null;
    }
  };

  return (
    <Layout 
      activeView={view} 
      onViewChange={setView} 
      onLogout={handleLogout}
      companyName={user.company}
      role={user.role}
      categoryFilter={categoryFilter}
      onCategoryFilterChange={setCategoryFilter}
    >
      <div className="relative h-full overflow-hidden flex flex-col">
        {/* Main Application Content - Responsive Padding */}
        <div className={`transition-all duration-700 flex-1 overflow-y-auto custom-scrollbar px-4 sm:px-6 md:px-8 lg:px-10 py-6 sm:py-8 lg:py-10 ${selectedSupplier ? 'opacity-20 blur-md scale-[0.98] pointer-events-none' : 'opacity-100 scale-100'}`}>
          {renderView()}
        </div>

        {/* Intelligence View Overlay */}
        {selectedSupplier && (
          <div className="fixed inset-0 z-50 bg-[#070b14]/90 backdrop-blur-xl overflow-y-auto animate-in slide-in-from-right-10 duration-500 shadow-2xl">
            <div className="max-w-[1600px] mx-auto p-4 sm:p-6 md:p-10 min-h-full">
              <IntelligenceView 
                supplier={selectedSupplier} 
                onBack={() => setSelectedSupplier(null)} 
              />
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

import React from 'react';
import { MOCK_SUPPLIERS, MOCK_DISRUPTIONS } from '../constants';
import { RiskStatus, Supplier } from '../types';
import { 
  AlertTriangle, 
  CheckCircle2, 
  Activity, 
  TrendingUp,
  Clock,
  ArrowUpRight,
  Target
} from 'lucide-react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer } from 'recharts';

interface DashboardViewProps {
  categoryFilter: string;
  statusFilter: RiskStatus | 'ALL';
  onStatusFilterChange: (status: RiskStatus | 'ALL') => void;
  onNavigateToRegistry: () => void;
  onNavigateToFeed: () => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ 
  categoryFilter, 
  statusFilter, 
  onStatusFilterChange,
  onNavigateToRegistry,
  onNavigateToFeed
}) => {
  const channelSuppliers = MOCK_SUPPLIERS.filter(s => {
    return categoryFilter === 'ALL' || s.category === categoryFilter;
  });

  const getCountByStatus = (status: RiskStatus) => channelSuppliers.filter(s => s.status === status).length;

  const stableCount = getCountByStatus(RiskStatus.STABLE);
  const cautionCount = getCountByStatus(RiskStatus.CAUTION);
  const riskyCount = getCountByStatus(RiskStatus.RISKY);
  const totalCount = channelSuppliers.length;

  const chartData = [
    { name: 'Stable', value: stableCount, color: '#059669', percentage: Math.round((stableCount/totalCount)*100) || 0, id: RiskStatus.STABLE },
    { name: 'Caution', value: cautionCount, color: '#D97706', percentage: Math.round((cautionCount/totalCount)*100) || 0, id: RiskStatus.CAUTION },
    { name: 'Risky', value: riskyCount, color: '#DC2626', percentage: Math.round((riskyCount/totalCount)*100) || 0, id: RiskStatus.RISKY },
  ].filter(d => d.value > 0).map(item => ({
    ...item,
    color: statusFilter === 'ALL' || statusFilter === item.id ? item.color : `${item.color}44`
  }));

  const stats = [
    { id: 'ALL', label: 'Network Total', value: totalCount, icon: Target, color: 'text-slate-600', bg: 'bg-slate-100', status: 'ALL' },
    { id: RiskStatus.RISKY, label: 'High Risk Nodes', value: riskyCount, icon: AlertTriangle, color: 'text-rose-600', bg: 'bg-rose-50', status: RiskStatus.RISKY },
    { id: RiskStatus.CAUTION, label: 'Active Caution', value: cautionCount, icon: Activity, color: 'text-amber-600', bg: 'bg-amber-50', status: RiskStatus.CAUTION },
    { id: RiskStatus.STABLE, label: 'Operational Sync', value: stableCount, icon: CheckCircle2, color: 'text-emerald-600', bg: 'bg-emerald-50', status: RiskStatus.STABLE },
  ];

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-[#0a0f1c] p-3 border border-white/10 shadow-xl rounded-xl">
          <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-1">{payload[0].name}</p>
          <p className="text-sm font-bold text-white">{payload[0].value} Suppliers ({payload[0].payload.percentage}%)</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 sm:space-y-10 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h2 className="text-3xl sm:text-4xl font-black text-white tracking-tight">Executive Intelligence</h2>
          <p className="text-slate-500 mt-2 font-medium flex flex-wrap items-center gap-2 text-xs sm:text-sm">
            <Clock size={16} className="text-blue-500" /> System sync completed {new Date().toLocaleTimeString()} • <span className="text-slate-200 font-bold">{categoryFilter}</span> Channel
          </p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <button className="flex-1 md:flex-none px-4 py-2.5 bg-white/5 border border-white/10 text-slate-300 font-bold rounded-xl hover:bg-white/10 transition-all text-xs sm:text-sm">
            Export
          </button>
          <button className="flex-1 md:flex-none px-4 py-2.5 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-500 transition-all shadow-lg shadow-blue-900/20 flex items-center justify-center gap-2 text-xs sm:text-sm">
            Resync <TrendingUp size={16} />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6">
        {stats.map((stat) => (
          <button 
            key={stat.id} 
            onClick={() => onStatusFilterChange(stat.status as any)}
            className={`text-left bg-[#0a0f1c] p-5 sm:p-7 rounded-2xl sm:rounded-3xl border transition-all group relative overflow-hidden h-full ${
              statusFilter === stat.status 
                ? 'border-blue-500 shadow-xl shadow-blue-500/10' 
                : 'border-white/5 shadow-sm hover:border-white/10'
            }`}
          >
            <div className={`inline-flex p-3 sm:p-4 rounded-xl sm:rounded-2xl bg-white/5 ${stat.color} mb-4 sm:mb-6 transition-transform group-hover:scale-110`}>
              <stat.icon size={22} />
            </div>
            <p className="text-slate-500 font-bold text-[10px] sm:text-xs uppercase tracking-widest">{stat.label}</p>
            <h3 className="text-2xl sm:text-4xl font-black text-white mt-1 sm:mt-2">{stat.value}</h3>
            {statusFilter === stat.status && (
              <div className="absolute top-4 right-4 text-[8px] font-black text-blue-400 uppercase tracking-tighter">Active Filter</div>
            )}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 sm:gap-10">
        <div className="xl:col-span-2 bg-[#0a0f1c] p-6 sm:p-10 rounded-[2rem] sm:rounded-[2.5rem] border border-white/5 shadow-sm flex flex-col items-center justify-center relative overflow-hidden min-h-[400px] sm:min-h-[500px]">
          <div className="absolute top-6 sm:top-10 left-6 sm:left-10">
            <h3 className="text-xl sm:text-2xl font-black text-white">Network Resilience</h3>
            <p className="text-slate-500 font-medium text-xs sm:text-sm mt-1">Node status distribution</p>
          </div>

          <div className="w-full h-[250px] sm:h-[350px] md:h-[400px] mt-10">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius="60%"
                  outerRadius="85%"
                  paddingAngle={5}
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={800}
                >
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} strokeWidth={0} className="outline-none" />
                  ))}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
              </PieChart>
            </ResponsiveContainer>

            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center mt-6">
              <p className="text-2xl sm:text-4xl font-black text-white">
                {statusFilter === 'ALL' ? totalCount : channelSuppliers.filter(s => s.status === statusFilter).length}
              </p>
              <p className="text-[8px] sm:text-[10px] font-black text-slate-500 uppercase tracking-widest mt-0.5 sm:mt-1">
                {statusFilter === 'ALL' ? 'Active Nodes' : `${statusFilter} Nodes`}
              </p>
            </div>
          </div>

          <div className="flex flex-wrap gap-6 sm:gap-10 mt-6 justify-center">
            {chartData.map((item, i) => (
              <button 
                key={i} 
                onClick={() => onStatusFilterChange(item.id as RiskStatus)}
                className={`flex items-center gap-2 sm:gap-3 transition-all ${statusFilter !== 'ALL' && statusFilter !== item.id ? 'opacity-30 scale-95' : 'scale-100'}`}
              >
                <div className="w-2 h-2 sm:w-3 sm:h-3 rounded-full" style={{backgroundColor: item.color.length > 7 ? item.color.slice(0, 7) : item.color}} />
                <div className="text-left">
                  <p className="text-[10px] sm:text-xs font-black text-white uppercase tracking-tight">{item.name}</p>
                  <p className="text-[10px] sm:text-sm font-bold text-slate-500">{item.percentage}%</p>
                </div>
              </button>
            ))}
          </div>
        </div>

        <div className="bg-[#0a0f1c] p-6 sm:p-10 rounded-[2rem] sm:rounded-[2.5rem] border border-white/5 shadow-sm overflow-hidden flex flex-col h-[500px] xl:h-auto">
          <div className="flex justify-between items-center mb-6 sm:mb-8">
            <h3 className="text-xl sm:text-2xl font-black text-white">Risk Signals</h3>
            <button 
              onClick={onNavigateToFeed}
              className="p-2 bg-white/5 hover:bg-white/10 rounded-xl transition-all"
            >
              <ArrowUpRight size={18} className="text-white" />
            </button>
          </div>
          <div className="space-y-4 sm:space-y-5 flex-1 overflow-y-auto pr-2 custom-scrollbar">
            {MOCK_DISRUPTIONS.filter(d => categoryFilter === 'ALL' || d.type === categoryFilter || d.type === 'Logistics').map((d) => (
              <button 
                key={d.id} 
                onClick={onNavigateToFeed}
                className="w-full text-left p-5 sm:p-6 rounded-2xl bg-white/[0.03] border border-white/5 hover:bg-white/5 hover:border-white/10 transition-all group"
              >
                <div className="flex items-center justify-between mb-2">
                  <span className={`px-2 py-0.5 rounded-lg text-[9px] font-black uppercase tracking-widest ${
                    d.severity === 'High' ? 'bg-rose-500/20 text-rose-400' : 'bg-amber-500/20 text-amber-400'
                  }`}>
                    {d.severity} Priority
                  </span>
                  <span className="text-[9px] font-bold text-slate-500">{d.type}</span>
                </div>
                <h4 className="font-extrabold text-white text-sm sm:text-base leading-tight mb-2 truncate">{d.title}</h4>
                <p className="text-xs text-slate-500 line-clamp-2 leading-relaxed">{d.summary}</p>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;

import React, { useState } from 'react';
import { MOCK_SUPPLIERS } from '../constants';
import { RiskStatus, Supplier } from '../types';
import RiskBadge from '../components/RiskBadge';
import { MapPin, Info, ArrowRight, Activity, Zap, ShieldAlert, Target, Globe, ChevronDown, ChevronUp } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';

interface MapViewProps {
  categoryFilter: string;
  statusFilter: RiskStatus | 'ALL';
  onSelectSupplier: (s: Supplier) => void;
  hqLocation?: [number, number];
}

const MapView: React.FC<MapViewProps> = ({ categoryFilter, statusFilter, onSelectSupplier, hqLocation = [48.13, 11.58] }) => {
  const [hovered, setHovered] = useState<Supplier | null>(null);
  const [isTelemetryVisible, setIsTelemetryVisible] = useState(true);

  const filteredSuppliers = MOCK_SUPPLIERS.filter(s => {
    const matchesCategory = categoryFilter === 'ALL' || s.category === categoryFilter;
    const matchesStatus = statusFilter === 'ALL' || s.status === statusFilter;
    return matchesCategory && matchesStatus;
  });

  const getCoordinates = (lat: number, lng: number) => {
    const x = ((lng + 180) / 360) * 100;
    const y = ((90 - lat) / 180) * 100;
    return { x, y };
  };

  const hqPos = getCoordinates(hqLocation[0], hqLocation[1]);

  const chartData = [
    { name: 'Good', value: 37, color: '#10b981' },
    { name: 'Warning', value: 49, color: '#f59e0b' },
    { name: 'Error', value: 23, color: '#f43f5e' },
  ];

  return (
    <div className="flex flex-col xl:flex-row h-full animate-in fade-in duration-700 bg-[#070b14] -mx-4 sm:-mx-6 md:-mx-8 lg:-mx-10 -my-6 sm:-my-8 lg:-my-10">
      {/* Map Canvas */}
      <div className="flex-1 relative overflow-hidden bg-[#070b14] min-h-[400px] xl:min-h-0">
        <div className="absolute inset-0 opacity-10 pointer-events-none" 
             style={{ backgroundImage: 'radial-gradient(circle, #2563eb 1px, transparent 1px)', backgroundSize: '40px 40px' }} />

        <svg viewBox="0 0 100 100" className="absolute inset-0 w-full h-full preserve-3d">
          <path d="M10,20 Q30,15 40,25 T60,20 Q80,25 90,40 T70,60 Q50,70 30,65 T10,20" fill="none" stroke="#1e293b" strokeWidth="0.2" />

          {filteredSuppliers.map(s => {
            const pos = getCoordinates(s.coordinates[0], s.coordinates[1]);
            return (
              <line 
                key={`line-${s.id}`}
                x1={hqPos.x} y1={hqPos.y} 
                x2={pos.x} y2={pos.y} 
                stroke={s.status === RiskStatus.RISKY ? '#f43f5e' : '#2563eb'} 
                strokeWidth="0.08" 
                strokeDasharray="0.5,0.5"
                className="opacity-30 animate-[pulse_3s_infinite]"
              />
            );
          })}

          <circle cx={hqPos.x} cy={hqPos.y} r="1.2" fill="#2563eb" className="animate-pulse shadow-[0_0_10px_#2563eb]" />
          <circle cx={hqPos.x} cy={hqPos.y} r="0.4" fill="white" />

          {filteredSuppliers.map(s => {
            const pos = getCoordinates(s.coordinates[0], s.coordinates[1]);
            return (
              <g 
                key={s.id} 
                className="cursor-pointer group"
                onMouseEnter={() => setHovered(s)}
                onMouseLeave={() => setHovered(null)}
                onClick={() => onSelectSupplier(s)}
              >
                <circle 
                  cx={pos.x} cy={pos.y} r="1.5" 
                  fill={s.status === RiskStatus.RISKY ? '#f43f5e22' : '#2563eb22'} 
                  className="group-hover:scale-150 transition-transform duration-300"
                />
                <circle 
                  cx={pos.x} cy={pos.y} r="0.6" 
                  fill={s.status === RiskStatus.RISKY ? '#f43f5e' : s.status === RiskStatus.CAUTION ? '#f59e0b' : '#10b981'} 
                />
              </g>
            );
          })}
        </svg>

        <div className="absolute top-4 sm:top-6 left-4 sm:left-6 flex items-center gap-4">
          <div className="bg-[#0a0f1c]/80 backdrop-blur-md border border-white/10 rounded-xl p-2 sm:p-3 shadow-2xl">
            <h4 className="text-[8px] sm:text-[10px] font-black text-slate-500 uppercase tracking-widest mb-0.5 sm:mb-1">Active Region</h4>
            <div className="flex items-center gap-1.5 sm:gap-2">
              <Globe size={14} className="text-blue-400" />
              <span className="text-xs sm:text-sm font-bold text-white">{categoryFilter === 'ALL' ? 'Global Grid' : categoryFilter}</span>
            </div>
          </div>
        </div>

        {hovered && (
          <div 
            className="absolute z-50 pointer-events-none transition-all animate-in zoom-in-95 duration-200"
            style={{ 
              left: `${getCoordinates(hovered.coordinates[0], hovered.coordinates[1]).x}%`, 
              top: `${getCoordinates(hovered.coordinates[0], hovered.coordinates[1]).y - 4}%`,
              transform: 'translateX(-50%)'
            }}
          >
            <div className="bg-[#0a0f1c] border border-white/10 rounded-xl shadow-2xl px-2 py-1.5 flex items-center gap-2">
              <span className="text-[10px] font-bold text-white whitespace-nowrap">{hovered.name}</span>
              <div className={`w-1.5 h-1.5 rounded-full ${hovered.status === RiskStatus.RISKY ? 'bg-rose-500' : 'bg-emerald-500'}`} />
            </div>
          </div>
        )}
      </div>

      {/* Responsive Telemetry Panel */}
      <div className={`
        w-full xl:w-80 bg-[#0a0f1c] border-t xl:border-t-0 xl:border-l border-white/5 flex flex-col transition-all duration-300
        ${isTelemetryVisible ? 'h-auto max-h-[600px] xl:max-h-none' : 'h-12 xl:h-full overflow-hidden'}
      `}>
        <div 
          className="flex justify-between items-center p-4 sm:p-6 border-b border-white/5 xl:border-b-0 cursor-pointer xl:cursor-default"
          onClick={() => setIsTelemetryVisible(!isTelemetryVisible)}
        >
          <h3 className="text-base sm:text-lg font-bold text-white">Network Status</h3>
          <div className="flex items-center gap-3">
             <button className="hidden sm:block px-3 py-1 bg-blue-600/10 text-blue-400 text-[9px] font-black rounded border border-blue-500/20 uppercase">
               Analyze
             </button>
             <div className="xl:hidden text-slate-500">
               {isTelemetryVisible ? <ChevronDown size={20} /> : <ChevronUp size={20} />}
             </div>
          </div>
        </div>

        <div className="p-4 sm:p-6 space-y-4 sm:space-y-6 flex-1 overflow-y-auto custom-scrollbar">
          <div className="flex justify-between items-center">
            <span className="text-[10px] sm:text-xs font-bold text-slate-500 uppercase">Health Score</span>
            <span className="text-[10px] sm:text-xs font-bold text-amber-500 uppercase">Warning</span>
          </div>

          <div className="grid grid-cols-2 gap-3 sm:gap-4">
            <div className="bg-white/5 p-3 sm:p-4 rounded-xl border border-white/5">
              <span className="text-[8px] sm:text-[10px] font-black text-slate-500 uppercase block mb-0.5 sm:mb-1">Total Alerts</span>
              <span className="text-lg sm:text-xl font-bold text-white">321</span>
            </div>
            <div className="bg-white/5 p-3 sm:p-4 rounded-xl border border-white/5">
              <span className="text-[8px] sm:text-[10px] font-black text-slate-500 uppercase block mb-0.5 sm:mb-1">Sync Load</span>
              <span className="text-lg sm:text-xl font-bold text-white">0.82 Gb</span>
            </div>
          </div>

          <div className="relative h-32 sm:h-48 w-full flex items-center justify-center">
             <ResponsiveContainer width="100%" height="100%">
               <PieChart>
                 <Pie
                   data={chartData}
                   innerRadius="65%"
                   outerRadius="85%"
                   paddingAngle={5}
                   dataKey="value"
                 >
                   {chartData.map((entry, index) => (
                     <Cell key={`cell-${index}`} fill={entry.color} strokeWidth={0} />
                   ))}
                 </Pie>
               </PieChart>
             </ResponsiveContainer>
             <div className="absolute inset-0 flex flex-col items-center justify-center pt-2">
               <span className="text-xl sm:text-2xl font-black text-white">{filteredSuppliers.length}</span>
               <span className="text-[8px] sm:text-[10px] font-black text-slate-500 uppercase tracking-widest">Nodes</span>
             </div>
          </div>

          <div className="space-y-2 sm:space-y-3">
             {chartData.map((item) => (
               <div key={item.name} className="flex justify-between items-center px-2">
                 <div className="flex items-center gap-2">
                   <div className="w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full" style={{ backgroundColor: item.color }} />
                   <span className="text-[8px] sm:text-[10px] font-bold text-slate-400 uppercase">{item.name}</span>
                 </div>
                 <span className="text-[8px] sm:text-[10px] font-bold text-white">{item.value}</span>
               </div>
             ))}
          </div>

          <div className="pt-6 sm:pt-8 border-t border-white/5">
             <h4 className="text-[8px] sm:text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 sm:mb-4">Latest Operations</h4>
             <div className="space-y-3 sm:space-y-4">
               {[
                 { msg: 'Regional inspection complete', time: '2m ago', icon: Activity },
                 { msg: 'Alert: Heavy movement detected', time: '14m ago', icon: ShieldAlert },
               ].map((item, i) => (
                 <div key={i} className="flex gap-2 sm:gap-3">
                   <div className="w-7 h-7 sm:w-8 sm:h-8 rounded-lg bg-white/5 flex items-center justify-center text-slate-500 flex-shrink-0">
                     <item.icon size={12} />
                   </div>
                   <div className="overflow-hidden">
                     <p className="text-[10px] sm:text-xs font-bold text-slate-300 leading-tight truncate">{item.msg}</p>
                     <p className="text-[8px] sm:text-[10px] text-slate-500 mt-0.5 sm:mt-1 uppercase font-black">{item.time}</p>
                   </div>
                 </div>
               ))}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MapView;

import React, { useState } from 'react';
import { MOCK_SUPPLIERS } from '../constants';
import { Supplier, RiskStatus } from '../types';
import RiskBadge from '../components/RiskBadge';
import { Search, ChevronRight, MapPin, Mail, Filter } from 'lucide-react';

interface RegistryViewProps {
  categoryFilter: string;
  statusFilter: RiskStatus | 'ALL';
  onStatusFilterChange: (s: RiskStatus | 'ALL') => void;
  onSelectSupplier: (supplier: Supplier) => void;
}

