        <p className="text-slate-500 font-medium mt-1">
          {categoryFilter === 'ALL' ? 'Global Network' : `${categoryFilter} Channel`} Real-time Stream
        </p>
      </div>

      <div className="relative space-y-10 before:absolute before:left-6 before:top-4 before:bottom-4 before:w-0.5 before:bg-white/10">
        {filteredDisruptions.map((alert) => {
          const Icon = typeIcons[alert.type] || Info;
          return (
            <div key={alert.id} className="relative pl-16 group">
              <div className={`absolute left-0 top-0 w-14 h-14 rounded-[1.25rem] flex items-center justify-center z-10 border-4 border-[#070b14] transition-all shadow-xl ${
                alert.severity === 'High' ? 'bg-rose-900 text-white' : 'bg-amber-900 text-white'
              }`}>
                <Icon size={24} />
              </div>

              <div className="bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-sm hover:shadow-2xl transition-all duration-300">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <div className="flex items-center gap-4 mb-2">
                      <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${
                        alert.severity === 'High' ? 'bg-rose-100 text-rose-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {alert.severity} Priority
                      </span>
                      <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest flex items-center gap-2">
                        <Clock size={12} className="text-slate-300" /> {new Date(alert.timestamp).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                      </span>
                    </div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">{alert.title}</h3>
                  </div>
                  <button 
                    onClick={onNavigateToResources}
                    className="p-3 bg-slate-50 hover:bg-slate-100 rounded-2xl text-slate-400 transition-colors group"
                  >
                    <ExternalLink size={20} className="group-hover:text-blue-600 transition-colors" />
                  </button>
                </div>

                <div className="p-6 bg-slate-900 rounded-3xl mb-8 border border-slate-800 shadow-inner">
                  <p className="text-slate-300 text-sm leading-relaxed font-medium">
                    <span className="text-emerald-400 font-black uppercase text-[10px] tracking-widest block mb-2">GenAI Core Insight</span>
                    "{alert.summary}"
                  </p>
                </div>

                <div className="flex flex-wrap gap-8 items-center border-t border-slate-100 pt-8">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Impact Zone</span>
                    <span className="text-sm font-extrabold text-slate-900 uppercase">{alert.location}</span>
                  </div>
                  <div className="flex flex-col gap-2">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nodes Affected</span>
                    <div className="flex -space-x-3">
                      {alert.impactedSuppliers.map((id, i) => (
                        <div key={id} className="w-10 h-10 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[10px] font-black text-slate-600 shadow-sm" title={`Supplier ID: ${id}`}>
                          {id.toUpperCase()}
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {filteredDisruptions.length === 0 && (
        <div className="py-20 text-center bg-white/[0.03] rounded-[2.5rem] border border-dashed border-white/10">
          <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">No signals detected in this channel.</p>
        </div>
      )}

      <div className="text-center pt-8">
        <button 
          onClick={handleAccessArchival}
          className="px-8 py-4 bg-white text-slate-900 font-black uppercase tracking-widest text-[10px] rounded-2xl hover:bg-slate-100 transition-all shadow-xl flex items-center gap-3 mx-auto"
        >
          <Archive size={14} /> Access Archival Data
        </button>
      </div>
    </div>
  );
};

export default FeedView;

import React, { useState, useEffect } from 'react';
import { View, Supplier, User, RiskStatus } from './types';
import Layout from './components/Layout';
import AuthView from './views/AuthView';
import DashboardView from './views/DashboardView';
import RegistryView from './views/RegistryView';
import IntelligenceView from './views/IntelligenceView';
import MapView from './views/MapView';
import FeedView from './views/FeedView';
import SettingsView from './views/SettingsView';
import SubscriptionView from './views/SubscriptionView';
import ResourcesView from './views/ResourcesView';
import PaymentView from './views/PaymentView';

const App: React.FC = () => {
  const [view, setView] = useState<View>('DASHBOARD');
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('cg_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [categoryFilter, setCategoryFilter] = useState<string>('ALL');
  const [statusFilter, setStatusFilter] = useState<RiskStatus | 'ALL'>('ALL');
  const [selectedSupplier, setSelectedSupplier] = useState<Supplier | null>(null);
  const [selectedPlan, setSelectedPlan] = useState<{ name: string; price: string } | null>(null);

  const handleAuthComplete = (userData: User) => {
    setUser(userData);
    localStorage.setItem('cg_session', JSON.stringify(userData));
  };

  const handleLogout = () => {
    localStorage.removeItem('cg_session');
    setUser(null);
  };

  const navigateToSupplierIntelligence = (supplier: Supplier) => {
    setSelectedSupplier(supplier);
  };

  if (!user) {
    return <AuthView onComplete={handleAuthComplete} />;
  }

  const renderView = () => {
    switch (view) {
      case 'DASHBOARD':
        return (
          <DashboardView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            onNavigateToRegistry={() => setView('REGISTRY')}
            onNavigateToFeed={() => setView('FEED')}
          />
        );
      case 'REGISTRY':
        return (
          <RegistryView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onStatusFilterChange={setStatusFilter}
            onSelectSupplier={navigateToSupplierIntelligence} 
          />
        );
      case 'MAP':
        return (
          <MapView 
            categoryFilter={categoryFilter}
            statusFilter={statusFilter}
            onSelectSupplier={navigateToSupplierIntelligence}
          />
        );
      case 'FEED':
        return <FeedView categoryFilter={categoryFilter} onNavigateToResources={() => setView('RESOURCES')} />;
      case 'SETTINGS':
        return <SettingsView user={user} onNavigate={setView} />;
      case 'SUBSCRIPTION':
        return (
          <SubscriptionView 
            onBack={() => setView('SETTINGS')} 
            onNavigateToPayment={(plan) => {
              setSelectedPlan(plan);
              setView('PAYMENT');
            }} 
          />
        );
      case 'RESOURCES':
        return <ResourcesView onBack={() => setView('DASHBOARD')} />;
      case 'PAYMENT':
        return <PaymentView onBack={() => setView('SUBSCRIPTION')} selectedPlan={selectedPlan} />;
      default:
        return null;
    }
  };

  return (
    <Layout 
      activeView={view} 
      onViewChange={setView} 
      onLogout={handleLogout}
      companyName={user.company}
      role={user.role}
      categoryFilter={categoryFilter}
      onCategoryFilterChange={setCategoryFilter}
    >
      <div className="relative h-full overflow-hidden flex flex-col">
        {/* Main Application Content - Responsive Padding */}
        <div className={`transition-all duration-700 flex-1 overflow-y-auto custom-scrollbar px-4 sm:px-6 md:px-8 lg:px-10 py-6 sm:py-8 lg:py-10 ${selectedSupplier ? 'opacity-20 blur-md scale-[0.98] pointer-events-none' : 'opacity-100 scale-100'}`}>
          {renderView()}
        </div>

        {/* Intelligence View Overlay */}
        {selectedSupplier && (
          <div className="fixed inset-0 z-50 bg-[#070b14]/90 backdrop-blur-xl overflow-y-auto animate-in slide-in-from-right-10 duration-500 shadow-2xl">
            <div className="max-w-[1600px] mx-auto p-4 sm:p-6 md:p-10 min-h-full">
              <IntelligenceView 
                supplier={selectedSupplier} 
                onBack={() => setSelectedSupplier(null)}
                onNavigateToResources={() => {
                    setSelectedSupplier(null);
                    setView('RESOURCES');
                }}
              />
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

